import React from 'react';
import './Skills.css';

const Skills = () => {
  const skillCategories = [
    {
      name: "Frontend",
      skills: [
        { name: "React", level: 90 },
        { name: "JavaScript", level: 95 },
        { name: "TypeScript", level: 85 },
        { name: "HTML/CSS", level: 90 },
        { name: "Next.js", level: 80 }
      ]
    },
    {
      name: "Backend",
      skills: [
        { name: "Node.js", level: 88 },
        { name: "Python", level: 92 },
        { name: "Express", level: 85 },
        { name: "Django", level: 80 },
        { name: "PostgreSQL", level: 85 }
      ]
    },
    {
      name: "AI/ML",
      skills: [
        { name: "TensorFlow", level: 90 },
        { name: "PyTorch", level: 88 },
        { name: "Scikit-learn", level: 85 },
        { name: "OpenCV", level: 80 },
        { name: "NLP", level: 85 }
      ]
    }
  ];

  return (
    <section id="skills" className="section skills">
      <div className="container">
        <h2 className="section-title">Skills & Expertise</h2>
        <p className="section-subtitle">
          My technical skills and expertise across various technologies and domains.
        </p>

        <div className="skills-grid">
          {skillCategories.map((category, categoryIndex) => (
            <div key={categoryIndex} className="skill-category card">
              <h3 className="category-title">{category.name}</h3>
              <div className="skills-list">
                {category.skills.map((skill, skillIndex) => (
                  <div key={skillIndex} className="skill-item">
                    <div className="skill-header">
                      <span className="skill-name">{skill.name}</span>
                      <span className="skill-level">{skill.level}%</span>
                    </div>
                    <div className="skill-bar">
                      <div 
                        className="skill-progress" 
                        style={{ width: `${skill.level}%` }}
                      ></div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>

        <div className="skills-highlight">
          <div className="highlight-card card">
            <h3 className="highlight-title">Continuous Learning</h3>
            <p className="highlight-text">
              I'm constantly exploring new technologies and frameworks to stay at the forefront of innovation.
              My passion for learning drives me to master new skills and adapt to evolving industry standards.
            </p>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Skills;
